using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    // Create a document
    Ptr docs = app->documents();
    if (!docs)
        return false;
    Ptr doc = docs->add(adsk::core::DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr activeProd = app->activeProduct();
    if (!activeProd)
        return false;

    Ptr design = activeProd;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch.
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xzPlane = rootComp->xZConstructionPlane();
    if (!xzPlane)
        return false;
    Ptr sketch = sketches->add(xzPlane);
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr circle1 = sketchCircles->addByCenterRadius(centerPoint, 3.0);
    if (!circle1)
        return false;
    Ptr circle2 = sketchCircles->addByCenterRadius(centerPoint, 10.0);
    if (!circle2)
        return false;

    // Get the profiles defined by the circles
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr profile1 = profs->item(0);
    if (!profile1)
        return false;
    Ptr profile2 = profs->item(1);
    if (!profile2)
        return false;

    // Get the inner and outer profile
    Ptr areaPropertiesOfProfile1 = profile1->areaProperties();
    if (!areaPropertiesOfProfile1)
        return false;
    Ptr areaPropertiesOfProfile2 = profile2->areaProperties();
    if (!areaPropertiesOfProfile2)
        return false;
    double areaOfProfile1 = areaPropertiesOfProfile1->area();
    double areaOfProfile2 = areaPropertiesOfProfile2->area();
    Ptr outerProfile = profile1;
    if (areaOfProfile1  feats = rootComp->features();
    if (!feats)
        return false;
    Ptr extrudes = feats->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extrudeDistance = ValueInput::createByString("1 cm");
    if (!extrudeDistance)
        return false;
    Ptr extrudeFeature =
        extrudes->addSimple(outerProfile, extrudeDistance, FeatureOperations::NewBodyFeatureOperation);
    if (!extrudeFeature)
        return false;

    // Get BrepEdge from inner loop on the end face of the extrusion
    Ptr endFacesObj = extrudeFeature->endFaces();
    if (!endFacesObj)
        return false;
    Ptr endFace = endFacesObj->item(0);
    if (!endFace)
        return false;
    Ptr brepLoops = endFace->loops();
    if (!brepLoops)
        return false;
    Ptr innerLoop = brepLoops->item(0);
    if (!innerLoop)
        return false;
    if (innerLoop->isOuter())
    {
        innerLoop = brepLoops->item(1);
    }
    if (!innerLoop)
        return false;
    Ptr brepEdges = innerLoop->edges();
    if (!brepEdges)
        return false;
    Ptr brepEdge = brepEdges->item(0);
    if (!brepEdge)
        return false;

    // Create the patch feature
    Ptr patches = feats->patchFeatures();
    if (!patches)
        return false;
    Ptr patchInput =
        patches->createInput(brepEdge, adsk::fusion::FeatureOperations::NewBodyFeatureOperation);
    if (!patchInput)
        return false;
    Ptr patchFeature = patches->add(patchInput);
    if (!patchFeature)
        return false;


    return true;
}
